class LFUCache:
    def __init__(self, capacity: int):
        self.cap = capacity
        self.size = 0
        self.min_freq = 0
        self.nodes = {} # key -> node
        self.freqs = collections.defaultdict(collections.OrderedDict) # freq -> {key: val}
    def _update(self, node):
        f = node.freq
        self.freqs[f].pop(node.key)
        if not self.freqs[f] and f == self.min_freq: self.min_freq += 1
        node.freq += 1
        self.freqs[node.freq][node.key] = node
    def get(self, key):
        if key not in self.nodes: return -1
        node = self.nodes[key]
        self._update(node)
        return node.val
    def put(self, key, value):
        if self.cap == 0: return
        if key in self.nodes:
            node = self.nodes[key]
            node.val = value
            self._update(node)
        else:
            if self.size == self.cap:
                k, n = self.freqs[self.min_freq].popitem(last=False)
                del self.nodes[k]; self.size -= 1
            node = Node(key, value); self.nodes[key] = node
            self.freqs[1][key] = node; self.min_freq = 1; self.size += 1

